import{_ as t,o as a,c as r,a4 as n}from"./chunks/framework.BybBnFXO.js";const p=JSON.parse('{"title":"Aventurescence (Sunstone Glitter)","description":"","frontmatter":{"title":"Aventurescence (Sunstone Glitter)","phenomenon":"aventurescence"},"headers":[],"relativePath":"optical-phenomena/aventurescence.md","filePath":"optical-phenomena/aventurescence.md","lastUpdated":1784177547000}'),l={name:"optical-phenomena/aventurescence.md"};function s(o,e,i,c,h,d){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="aventurescence-sunstone-glitter" tabindex="-1">Aventurescence (Sunstone Glitter) <a class="header-anchor" href="#aventurescence-sunstone-glitter" aria-label="Permalink to &quot;Aventurescence (Sunstone Glitter)&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Aventurescence appears when a gem contains numerous small flat metallic platelets (most commonly hematite, copper, or goethite). Light reflecting off these platelets produces a sparkly metallic sheen. The classic examples are:</p><ul><li><strong>Sunstone</strong> — feldspar with hematite / goethite platelets</li><li><strong>Aventurine</strong> — quartz with chrome-mica or hematite platelets (green and brown varieties)</li><li><strong>Imperial Porphyry</strong> — feldspar variant Larger, more reflective platelets produce a stronger effect.</li></ul><h2 id="mechanism" tabindex="-1">Mechanism <a class="header-anchor" href="#mechanism" aria-label="Permalink to &quot;Mechanism&quot;">​</a></h2><p>Platelet reflection: during crystallization, hematite (Fe₂O₃) or goethite (FeO(OH)) precipitate as small hexagonal or round platelets ~0.1–1 mm in size, oriented along specific crystal planes. As light hits from varying angles, each platelet sparkles in turn, producing a metallic sun-fleck effect. Chrome-mica platelets in green aventurine reflect green light; red/brown variants reflect from hematite.</p><h2 id="example-gemstones" tabindex="-1">Example Gemstones <a class="header-anchor" href="#example-gemstones" aria-label="Permalink to &quot;Example Gemstones&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Gem</th><th>Plates</th><th>Host</th></tr></thead><tbody><tr><td>Sunstone (Oregon) / 日光石</td><td>copper / hematite</td><td>Feldspar (oligoclase / labradorite)</td></tr><tr><td>Aventurine Quartz (green) / 砂金石</td><td>chrome-mica / fuchsite</td><td>Quartz</td></tr><tr><td>Aventurine Quartz (red-brown) / 砂金石</td><td>hematite</td><td>Quartz</td></tr><tr><td>Imperial Sunstone / 帝王日光石</td><td>large copper platelets</td><td>Feldspar</td></tr></tbody></table><p><em>See the <a href="./intro.html">optical phenomena overview</a>.</em></p>',9)])])}const u=t(l,[["render",s]]);export{p as __pageData,u as default};
